import{_ as b,o as p,c as a,j as r,a as e,a1 as t}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"TRAUMA：英雄病","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/TRAUMA：英雄病.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/TRAUMA：英雄病.md"}'),T={name:"4.资源分区/6.技艺及称号/通用及综合类/TRAUMA：英雄病.md"};function R(M,A,U,s,n,o){return p(),a("div",null,[...A[0]||(A[0]=[r("h1",{id:"trauma-英雄病",tabindex:"-1"},[e("TRAUMA：英雄病 "),r("a",{class:"header-anchor",href:"#trauma-英雄病","aria-label":'Permalink to "TRAUMA：英雄病"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),t('<h1 id="trauma-英雄病-1" tabindex="-1">TRAUMA：英雄病 <a class="header-anchor" href="#trauma-英雄病-1" aria-label="Permalink to &quot;TRAUMA：英雄病&quot;">​</a></h1><p>英雄病<br> 描述：在某个世界中，拥有成为英雄的资格的存在会明显的表现出与常人不同的一点，即眼瞳变色。<br> 据普遍统计，大致上的类似的存在都有着TRAUMA，即过往经历与个人性格留下的心理性创伤，所形成的产物就是被称为【英雄病】的症状，眼瞳变色是英雄们发症时最显著的表现……请由衷的相信他们即使发症也不会有问题吧。</p><p>TRAUMA：不信<br> 价格：C+1000<br> 瞳色：红色<br> 分类：愤怒<br> 描述：神真的是存在的吗？那是一切的开始。噩梦般的每日，反转的日常、世界。还是孩子的我就慨叹于狂气，慨叹于绝望。如果神明不存在于世界，为何却将我的生活弄的一塌糊涂？我也发誓一定要结束这一切，无论有多少难关，无论要付出多少代价，我，绝不放弃。<br> 效果：你在承受恐惧或类恐惧的不良点数时，将恐惧不良点数转化为【愤怒】不良点数。<br> 你常时承受自身传奇决心*1点愤怒不良点数（无目标来源），你可以在受到攻击时选择增加针对攻击你目标的愤怒不良点数，数值等同传奇决心*1，上限为决心/耐力取高。</p><p>【愤怒】：在攻击对你造成转化前不良点数的对象上获得等量士气加值。对该对象使用互动系技能、使用心智属性的特殊能力判定上受到减值。<br> 在对愤怒对象以外的敌人时，基础防御＋闪避防御＋格挡防御的总和上也受到减值（按照格挡防御、闪避防御、基础防御的顺序进行减少）。</p><p>若计算本能力带来的异常点数进入严重后果，则TRAUMA开花，进入【大罪愤怒之绝望】状态。<br> 【大罪愤怒之绝望】：对世界的诅咒，是无法信任他人的状态。<br> 陷入该状态下，愤怒不良点数带来的加值上限恒定为自身耐力/决心取高，溢出的部分作为计数，不会带来任何好处但会带来减值，此时你不信任任何人，在战斗中会随机攻击所有单位，这是一个C级的混乱效果，但无法被你的能力所免疫。</p><p>此外，由于过量的愤怒，你无法进行任何需要静心来的动作，他无法获得除自然休息之外的好处，因此无法自然恢复愤怒不良点数，也无法进行周期在分钟以上的延长动作。</p><p>扮演限制：产生恐惧的场合，你只会产生愤怒，你无法隐藏对剧情世界中【宗教】或【圣职者】的敌意，接触时排除【友好】行动，最好的态度也只是【中立】行径。<br> 但主神与相关宗教系兑换不在敌意之中，主神明显是强大到不可理喻的存在而不是传统意义上的神明，而宗教系的兑换不过是相信着主神带来的好处（至少你是这样认为的）。</p><p>TRAUMA：孤独<br> 价格：C+1000<br> 瞳色：青色<br> 分类：嫉妒<br> 描述：只有我总是一个人，为什么？为什么我就没有一点才能？为什么要和能承认我的同伴分开，只有这件事绝对不能接受。<br> 效果：<br> 你始终承受等同自身决心/风度取高的嫉妒不良点数，效果等同魅惑不良点数，来源为【同伴】。<br> 因这个特性受到的嫉妒不良点数无法被移除，而只能暂时无效或者压制。<br> 你免疫除这个效果以外魅惑不良点数带来的减值，在使用意志抵抗对于其他目标的效果时，获得等同上述提到魅惑不良点数的加值。</p><p>该能力是未成熟的TRAUMA，因此距离开花尚且遥远，在购买也不会获得自由属性。但只要承受了不超过C级以上的，来自同伴以外的心灵影响效果或是魅惑不良点数的严重后果时，就会陷入【TRAUMA：疯狂】，而不是【大罪嫉妒之绝望】。<br> 【TRAUMA：疯狂】：陷入该状态下，嫉妒不良点数带来的加值上限恒定为自身决心/风度取高。<br> 无差别攻击感知范围中除了认定是同伴以外的单位，直到对你造成心灵来源影响的目标死亡，或是对应的魅惑不良点数消失。<br> 虽说如此，你依旧会陷入针对同伴以外的魅惑严重或毁灭后果的影响，此时计算对应影响等级，如果超过C级可以如常影响你，不超过C级则比较等级高低，等级相同会和来自同伴的指令相互覆盖，后者覆盖前者。</p><p>扮演限制：不会主动与认定的同伴分离，身边至少要有一个认定同伴的存在。若强硬的被分离，则立刻陷入【TRAUMA：疯狂】，直到回到同伴身边为止。</p><p>TRAUMA：过欲<br> 价格：B+2000<br> 瞳色：黄色<br> 分类：贪婪<br> 描述：我想要，仅此而已。会因为特定行为而积累贪欲，不择手段的紧跟自己执着的目标。<br> 效果：你始终承受等同自身决心/风度取高的贪欲不良点数，除TRAUMA外的能力对你造成魅惑不良点数时，转变为贪欲不良点数，这些点数来源为你指定的【贪欲目标】，贪欲目标通常只能存在一个（可选择转变目标），或者是其他对你造成了魅惑不良点数的单位。</p><p>你可以选择每轮再获得传奇决心/1点贪欲点数，超过上限点数不会造成任何影响，只在计算减少和是否进入严重/毁灭状态时计算。</p><p>【贪欲】：在针对来源的社交检定上，获得等同贪欲不良点数士气加值。<br> 只要具有贪欲不良点数，你就免疫所有魅惑或类魅惑不良点数带来的减值。</p><p>若计算本能力带来的异常点数进入严重后果，则TRAUMA开花，此时严重后果将被替换为：【大罪贪婪之绝望】。<br> 【大罪贪婪之绝望】：无法触及的指尖，无法触及之物，“不对、才不对，我想要的是”<br> 陷入该状态下，贪欲不良点数带来的加值上限恒定为自身耐力/决心取高<br> 你在对抗贪欲目标试图不被找到，或不被认出来的行为时，获得相当于你决心的DP加值，就像是承受迷情的严重/毁灭性后果一样。<br> 你必须攻击贪欲目标，直到将其击杀并夺取对方的尸体，即使是对方试图下达命令，这是一个B级心灵来源的胁迫效果，胁迫效果来源为【自身】。你无法自行免疫这个效果，除非对方具有更高等级的类似效果，才能在命令中阻止你，同等级即使在自己的回合里通过命令阻止你的行动，下次轮到你的时候也会覆盖此命令。</p><p>扮演限制：认定一项事物，时不时的亲近或索求对方，但不仅不要求必须得到，一旦对方真的同意了你的索求，那么就会因为【比起考虑自己先考虑你，已经不像是自己希望得到的存在】而立刻进入【大罪贪婪之绝望】的状态。<br> 此外，购买该能力不会获得自由属性。</p><p>TRAUMA：恶食<br> 价格：C+1500<br> 瞳色：茶色<br> 分类：暴食<br> 描述：狂气就是至高之蜜，若是能用意志将开花之物硬是抑制，这样的自律之人更是无上的甘露。<br> 效果：贪图【TRAUMA】的行径却能够作为TRAUMA的抑制剂来使用。<br> 你获得2点异常不良点数治疗（医疗点数48），由此获得的治疗点数可以临时为接触到的单位产生效果，视为进食对方的TRAUMA，从而带来恢复的作用，如果是恒定的部分只能暂时无效，无效的时间为直到下次长休息前。<br> 若你需要进食，则以进食TRAUMA或异常点数代替正常进食。</p><p>异相之微笑：TRAUMA：恶食是在理智的状态下所演绎狂人，因此主动发起的交涉检定会自动失败，在画风表现上已经的处于开花阶段，具有【大罪暴食之绝望】的状态。</p><p>扮演限制：时常对TRAUMA或狂气产生饥饿的欲望，若每日不能进食至少一次，则立刻如同没有正常进食一样产生疲乏点数的检定，用决心取代耐力判定DC，以意志豁免取代强韧进行这次检定。</p><p>TRAUMA：强制<br> 价格：C+1000<br> 瞳色：水色<br> 分类：傲慢<br> 描述：无尽的强制，不允许也不可能，会激烈的拒绝放弃的选择。<br> “我是你的同类，你是我的同类，那里不存在妥协，我们就是那样的生物。”<br> 效果：<br> 你是绝对自立，绝不妥协的人，因此你免疫C级别幻像、影响心灵来源的负面效果。</p><p>谎言即是妥协，因此你可以进行侦查检定对抗他人的对应社交检定，成功后立刻辨别出对方是否在说谎，也能用来辨认他人的情绪（如开心，冷漠，忌惮等），这是一个C级别、影响心灵来源的读心效果。</p><p>虽然【大罪傲慢之绝望】存在，但绝不妥协的强制不会进入开花阶段，开花本身就是一种妥协。他人在妥协的那一刻就不会是你的同类。</p><p>扮演限制：绝不后退，绝不退缩，苛求身边的同伴不放弃任何一次战斗或已决定好的目标（战斗无法取得胜利或目标已经失败仍可以正常撤退或放弃，因为已经得到结果了）。</p><p>TRAUMA：救济<br> 价格：C+1000<br> 瞳色：蓝色<br> 分类：怠惰<br> 描述：救济之谛观，反正不会被拯救，这样强烈的谛观之征兆会剥夺所有使人站立的勇气。<br> 效果：<br> 你在承受沮丧或类沮丧的不良点数时，将沮丧不良点数转化为【救济】不良点数。<br> 你常时承受自身传奇决心*1点救济不良点数（无目标来源），你可以战斗中每轮选择增加传奇决心*1的救济不良点数。</p><p>【救济】：在防御上获得等同救济点数的士气加值，但在所有延长动作的判定上受到等同救济点数的减值。</p><p>若计算本能力带来的异常点数进入严重后果，则TRAUMA开花，进入【大罪救济之绝望】状态。<br> 【大罪怠惰之绝望】：陷入该状态下，救济不良点数的加值上限恒定为决心，溢出的部分作为计数，不会带来任何好处但会带来减值。<br> 此时你不会愿意去做出任何使情况好转或恶化的事，即使是同样持有TRAUMA技能角色的意愿。<br> 除非接到确切无疑并且不可反抗的命令，否则不会做出任何主动动作，还会在所有行动上承受沮丧的减值，并且无法使用闪避或格挡防御。</p><p>扮演限制：只能和持有TRAUMA的角色正常沟通，呈现出厌世而不愿意做出任何行动的表现，除非是同样持有TRAUMA的单位传达的意愿或命令。</p><p>TRAUMA：幸福<br> 价格：C+1000<br> 瞳色：粉色<br> 分类：色欲<br> 描述：毫无疑问，这就是对于我的惩罚，应该感谢一切痛苦，那是幸福的事情，大家也是这样认为的吧？<br> 效果：你在承受剧痛或类剧痛的不良点数时，将剧痛不良点数转化为【幸福】不良点数。<br> 你常时承受自身决心/风度*1点幸福不良点数，来源视为能与你正常沟通的【所有单位】。</p><p>【幸福】：对抗来源目标的社交技能检定，和以意志抵抗其沉迷目标的特异或魔幻特殊能力时受到士气减值。</p><p>只要你承受了幸福不良点数，那么可以在一次攻击中附加本效果，使用目标以强韧检定豁免最终造成的伤害，豁免成功不会降低伤害，但豁免失败目标就无法对你进行攻击，即使范围攻击也会有意避开你，持续到你的下回合开始为止，这是一个C级创伤来源的支配效果。</p><p>若计算本能力带来的异常点数进入严重后果，则TRAUMA开花，进入【大罪幸福之绝望】状态。<br> 【大罪幸福之绝望】：陷入该状态下，你视为无助状态，无法主动作进行任何动作，也无法行动。</p><p>扮演限制：说好听一点是具有侍奉精神，说难听一点就是会盲目依赖所认识异性角色，基本无条件接受交欢的行为。会优先依赖熟人，在战斗中也会劝诱别人接受痛苦的事情。</p><p>TRAUMA：希望<br> 价格：B+2000<br> 瞳色：深蓝色<br> 描述：绝望即是希望，不需要依赖任何事物，人不是软弱的生物，不可能输给这种程度的东西，不过是因为有退路才会无法面对。<br> “因为无法相信那就灭亡死绝，是小孩子吗。这个世界上的我最可怜什么的，已经早就毕业了。”<br> 效果：你免疫所有【情绪异常】不良点数代带来的减值，包括恐惧、魅惑、亢奋、沮丧、承受对应的严重或毁灭性后果时，一律转变为【震慑】。<br> TRAUMA：希望没有开花阶段，更不存在对应的大罪。如果有对应的大罪，那么只会是绝望，然而TRAUMA：希望不会反转为绝望。<br> 扮演限制：无。不过，你不会被迫表现出被负面情绪或者其他情绪影响，也不会因任何原因而屈服。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',34)])])}const l=b(T,[["render",R]]);export{_ as __pageData,l as default};
